<?php
session_start();

class ImageProcessor {
    private $uploadDir = 'uploads/';
    private $outputDir = 'processed/';
    private $allowedFormats = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'tiff'];
    private $maxFileSize = 10485760; // 10MB
    
    public function __construct() {
        if (!is_dir($this->uploadDir)) {
            mkdir($this->uploadDir, 0755, true);
        }
        if (!is_dir($this->outputDir)) {
            mkdir($this->outputDir, 0755, true);
        }
    }
    
    public function processImage($file, $format, $width, $height, $quality = 85) {
        $errors = $this->validateInput($file, $format, $width, $height, $quality);
        if (!empty($errors)) {
            return ['success' => false, 'errors' => $errors];
        }
        
        $uploadedFile = $this->handleUpload($file);
        if (!$uploadedFile['success']) {
            return $uploadedFile;
        }
        
        $inputPath = $uploadedFile['path'];
        $outputFilename = uniqid('img_', true) . '.' . strtolower($format);
        $outputPath = $this->outputDir . $outputFilename;
        
        $result = $this->convertImage($inputPath, $outputPath, $format, $width, $height, $quality);
        
        if (file_exists($inputPath)) {
            unlink($inputPath);
        }
        
        return $result;
    }
    
    private function validateInput($file, $format, $width, $height, $quality) {
        $errors = [];
        
        if (!isset($file['tmp_name']) || !is_uploaded_file($file['tmp_name'])) {
            $errors[] = 'Invalid file upload';
        }
        
        if ($file['size'] > $this->maxFileSize) {
            $errors[] = 'File size exceeds maximum allowed size';
        }
        
        if (!in_array(strtolower($format), $this->allowedFormats)) {
            $errors[] = 'Invalid output format';
        }
        
        if (!is_numeric($width) || $width < 1 || $width > 10000) {
            $errors[] = 'Invalid width value';
        }
        
        if (!is_numeric($height) || $height < 1 || $height > 10000) {
            $errors[] = 'Invalid height value';
        }
        
        if (!is_numeric($quality) || $quality < 1 || $quality > 100) {
            $errors[] = 'Invalid quality value';
        }
        
        $finfo = finfo_open(FILEINFO_MIME_TYPE);
        $mimeType = finfo_file($finfo, $file['tmp_name']);
        finfo_close($finfo);
        
        $allowedMimes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/bmp', 'image/tiff'];
        if (!in_array($mimeType, $allowedMimes)) {
            $errors[] = 'Invalid file type';
        }
        
        return $errors;
    }
    
    private function handleUpload($file) {
        $filename = uniqid('upload_', true) . '_' . basename($file['name']);
        $filepath = $this->uploadDir . $filename;
        
        if (move_uploaded_file($file['tmp_name'], $filepath)) {
            return ['success' => true, 'path' => $filepath];
        }
        
        return ['success' => false, 'errors' => ['Failed to upload file']];
    }
    
    private function convertImage($inputPath, $outputPath, $format, $width, $height, $quality) {
        $inputPath = escapeshellarg(realpath($inputPath));
        $outputPath = escapeshellarg($outputPath);
        $width = (int)$width;
        $height = (int)$height;
        $quality = (int)$quality;
        
        $command = "convert $inputPath -resize {$width}x{$height} -quality $quality $outputPath 2>&1";
        
        $output = [];
        $returnCode = 0;
        exec($command, $output, $returnCode);
        
        if ($returnCode !== 0 || !file_exists(str_replace("'", "", $outputPath))) {
            return [
                'success' => false,
                'errors' => ['Image conversion failed: ' . implode("\n", $output)]
            ];
        }
        
        return [
            'success' => true,
            'output_file' => basename(str_replace("'", "", $outputPath)),
            'output_path' => str_replace("'", "", $outputPath),
            'download_url' => $this->outputDir . basename(str_replace("'", "", $outputPath))
        ];
    }
}

$processor = new ImageProcessor();

if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_FILES['image'])) {
    $format = $_POST['format'] ?? 'jpg';
    $width = $_POST['width'] ?? 800;
    $height = $_POST['height'] ?? 600;
    $quality = $_POST['quality'] ?? 85;
    
    $result = $processor->processImage($_FILES['image'], $format, $width, $height, $quality);
    
    if ($result['success']) {
        $_SESSION['message'] = 'Image processed successfully!';
        $_SESSION['result'] = $result;
    } else {
        $_SESSION['errors'] = $result['errors'];
    }
    
    header('Location: ' . $_SERVER['PHP_SELF']);
    exit;
}

$message = $_SESSION['message'] ?? null;
$errors = $_SESSION['errors'] ?? null;
$result = $_SESSION['result'] ?? null;
unset($_SESSION['message'], $_SESSION['errors'], $_SESSION['result']);
